@@ -0,0 +1,168 @@
+import LooseObject from '../../data/LooseObject';
+import { DotUtil } from '../../utils/DotUtil';
+import { dotCommon, dotNoNeedParmas } from '../../data/DotData';
+import { MmsUtil } from '../../utils/MmsUtil';
+import { ContactAvatar } from '../conversation/ContactAvatar';
+import { FavoriteName } from './FavoriteName';
+import { bubbleText } from '../conversation/bubbleText';
+import { FavoriteSlideComponent } from './FavoriteSlideComponent';
+import { MmsContentImage } from '../conversation/MmsContentImage';
+import FavoriteController from './favoriteController';
+
+@Reusable
+@Component
+export struct FavoriteListItemContent {
+  @State item: LooseObject = {};
+  @State itemIndex: number = 0;
+  @State isShowHead: boolean = true;
+  @State textDirection: string = 'ltr';
+  @State isPC: boolean = false;
+  @State isPad: boolean = false;
+  @State padMargin: number = 0;
+  @State screenWidth: number = 0;
+  @Link mFavoriteCtrl: FavoriteController;
+  @Link pageInfos: NavPathStack;
+  @Link listScroller: Scroller;
+  @Link scrollEndIndex: number;
+  @Link scrollStartIndex: number;
+  favoriteContentAlignRules: AlignRuleOption = {};
+  onMultiSelect: (selectIndex: number) => void = () => {};
+  onDelete: (deleteItem: LooseObject) => void = () => {};
+  buildMmsContentMap: (item: LooseObject, index: number, id: string) => void = () => {};
+
+  aboutToReuse(params: Record<string, ESObject>) {
+    this.item = params.item;
+    this.itemIndex = params.itemIndex;
+    this.isShowHead = params.isShowHead;
+    this.textDirection = params.textDirection;
+    this.isPC = params.isPC;
+    this.isPad = params.isPad;
+    this.padMargin = params.padMargin;
+    this.screenWidth = params.screenWidth;
+  }
+
+  build() {
+    RelativeContainer() {
+      if (this.isShowHead) {
+        if (this.item.senderNumber) {
+          if (this.item?.isChatbotMessage) {
+            ContactAvatar({
+              rawContactId: '',
+              contactId: '',
+              item: this.item
+            })
+              .margin(this.textDirection === 'rtl' ?
+                { top: 16, right: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_right') } :
+                { top: 16, left: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_left') })
+              .id('favorite_list_avatar')
+              .onClick(() => {
+                this.pageInfos.pushPathByName('RcsDetailsChatbotActivity', {
+                  id: this.item.senderNumber,
+                  icon: ''
+                } as LooseObject);
+                DotUtil.getInstance().reportEvent(dotNoNeedParmas, dotCommon.eventName.OPEN_CHATBOT_DETAIL);
+              })
+          } else {
+            ContactAvatar({
+              hasYellowPageIcon: this.mFavoriteCtrl.nameAndPicture(this.item.senderNumber)?.hasYellowPageIcon,
+              yellowPageId: this.mFavoriteCtrl.nameAndPicture(this.item.senderNumber)?.yellowPageId,
+              rawContactId: this.mFavoriteCtrl.contactIdMap.get(this.item.senderNumber) ?? '',
+              contactId: this.mFavoriteCtrl.contactIdMap.get(this.item.senderNumber) ?? '',
+              item: this.item,
+            })
+              .onClick(() => {
+                this.mFavoriteCtrl.titleBarAvatar(this.context, this.item.senderNumber);
+              })
+              .margin(this.textDirection === 'rtl' ?
+                { top: 16, right: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_right') } :
+                { top: 16, left: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_left') })
+              .id('favorite_list_avatar')
+          }
+        } else {
+          ContactAvatar({
+            rawContactId: this.mFavoriteCtrl.nameNoPicture('')?.rawContactId,
+            contactId: this.mFavoriteCtrl.nameNoPicture('')?.contactId,
+            item: this.item
+          })
+            .margin(this.textDirection === 'rtl' ?
+              { top: 16, right: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_right') } :
+              { top: 16, left: this.isPC ? 24 : this.isPad ? this.padMargin : $r('sys.float.margin_left') })
+            .id('favorite_list_avatar')
+        }
+      }
+      FavoriteName({
+        hasYellowPageIcon: this.mFavoriteCtrl.nameAndPicture(this.item.senderNumber)?.hasYellowPageIcon,
+        item: this.item,
+        isPad: this.isPad,
+        isShowHead: this.isShowHead,
+        textDirection: this.textDirection,
+      })
+      if (this.item.msgType === 0 || this.item.msgType === 2) {
+        bubbleText({
+          conversationCtrl: this.mFavoriteCtrl,
+          content: this.item.msgContent,
+          item: this.item,
+          itemIndex: this.itemIndex,
+          bubbleTextBackgroundColor: this.item.isSender === 0 ? $r('app.color.brand') : $r('sys.color.ohos_id_color_card_bg'),
+          isAdvancedSecurity: this.item.isAdvancedSecurity,
+          isSender: this.item.isSender,
+          detectResContent: this.item.detectResContent,
+          textDirection: this.textDirection,
+          listScroller: this.listScroller,
+          scrollEndIndex: this.scrollEndIndex,
+          scrollStartIndex: this.scrollStartIndex,
+          menuMultSelect: (selectIndex: number) => {
+            this.onMultiSelect(this.itemIndex);
+          },
+          menuDeleteCallBack: (deleteItem: LooseObject) => {
+            this.onDelete(deleteItem);
+          }
+        }).margin({ top: 4, bottom: 8 })
+          .alignRules(this.favoriteContentAlignRules)
+          .id('favorite_list_content')
+      } else if (this.item.msgType === 1) {
+        if (MmsUtil.isSlideType(this.item.contentType)) {
+          FavoriteSlideComponent({
+            itemIndex: this.itemIndex,
+            item: this.item,
+            listScroller: this.listScroller,
+            scrollEndIndex: this.scrollEndIndex,
+            scrollStartIndex: this.scrollStartIndex,
+            menuMultSelect: (selectIndex: number) => {
+              this.onMultiSelect(selectIndex);
+            },
+            menuDeleteCallBack: (deleteItem: LooseObject) => {
+              this.onDelete(deleteItem);
+            }
+          }).alignRules(this.favoriteContentAlignRules)
+            .id('favorite_list_content')
+        } else if (this.mFavoriteCtrl.mmsScreening(this.item.msgId, 8)) {
+          this.buildMmsContentMap(this.item, this.itemIndex, 'favorite_list_content')
+        } else if (!this.item.msgContent && this.mFavoriteCtrl.mmsScreening(this.item.msgId, 1)) {
+          MmsContentImage({
+            imageProps: this.mFavoriteCtrl.mmsScreening(this.item.msgId, 1).locationPath ?? '',
+            ct: this.mFavoriteCtrl.mmsScreening(this.item.msgId, 1).ct ?? '',
+            screenWidth: this.screenWidth,
+            itemIndex: this.itemIndex,
+            item: this.item,
+            listScroller: this.listScroller,
+            scrollEndIndex: this.scrollEndIndex,
+            scrollStartIndex: this.scrollStartIndex,
+            menuMultSelect: (selectIndex: number) => {
+              this.onMultiSelect(selectIndex);
+            },
+            menuDeleteCallBack: (deleteItem: LooseObject) => {
+              this.onDelete(deleteItem);
+            }
+          }).alignRules(this.favoriteContentAlignRules)
+            .id('favorite_list_content')
+        }
+      }
+    }
+  }
+}

